#include<iostream>#include<algorithm>#include<cmath>#include<vector>#include<climits>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;                vector<ll>pairs[1001];        for(ll i=1;i<=1000;i++){            for(ll j=1;j<=1000;j++){                if(__gcd(i,j)==1){                    pairs[i].push_back(j);                }            }        }        vector<ll>idx(1001);        for(ll i=0;i<n;i++){            ll x;            cin>>x;            idx[x]=i+1;        }        ll ans=-1;        for(ll i=1;i<=1000;i++){            if(idx[i]==0)continue;            for(ll j:pairs[i]){                if(idx[j]!=0){                    ans= max(ans, idx[j] + idx[i]);                }            }        }        cout<<ans<<"\n";    }}